macro.implementation:
do {
  osalSysLockFromISR();
  if ((dacp)->sync_state == (state)) {
    osalThreadResumeI(&(dacp)->thread, MSG_OK);
  }
  osalSysUnlockFromISR();
} while (false)

do {
  osalSysLockFromISR();
  osalThreadResumeI(&(dacp)->thread, MSG_RESET);
  osalSysUnlockFromISR();
} while (false)

do {
  dac_lld_stop_conversion(dacp);
  (dacp)->errors |= (err);
  __cbdrv_invoke_cb_with_transition(dacp,
                                    HAL_DRV_STATE_ERROR,
                                    HAL_DRV_STATE_READY);
  (dacp)->grpp = NULL;
  _dac_error_wakeup_isr(dacp);
} while (false)

types.verbatim:
typedef struct hal_dac_driver DACDriver;
typedef struct hal_dac_config DACConfig;
typedef struct hal_dac_conversion_group DACConversionGroup;

/* Inclusion of LLD header.*/
#include "hal_dac_lld.h"

objinit.implementation:
self->samples = NULL;
self->depth   = 0U;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;
#if DAC_USE_SYNCHRONIZATION == TRUE
self->thread     = NULL;
self->sync_state = HAL_DRV_STATE_STOP;
#endif

method.implementation:
osalDbgCheck(channel < (dacchannel_t)DAC_MAX_CHANNELS);
osalDbgAssert((self->state == HAL_DRV_STATE_READY)  ||
              (self->state == HAL_DRV_STATE_ACTIVE) ||
              (self->state == HAL_DRV_STATE_HALF)   ||
              (self->state == HAL_DRV_STATE_FULL),
              "invalid state");

return dac_lld_put_channel(self, channel, sample);

msg_t msg;

osalDbgCheckClassI();
osalDbgCheck((self != NULL) && (grpp != NULL) && (samples != NULL) &&
             (depth > 0U) && ((depth == 1U) || ((depth & 1U) == 0U)));
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "not ready");

self->samples = samples;
self->depth   = depth;
self->grpp    = grpp;
self->events  = 0U;
self->errors  = 0U;
self->state   = HAL_DRV_STATE_ACTIVE;
msg = dac_lld_start_conversion(self);
if (msg != HAL_RET_SUCCESS) {
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
}

return msg;

msg_t msg;

osalSysLock();
msg = dacStartConversionI(self, grpp, samples, depth);
osalSysUnlock();

return msg;

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert((self->state == HAL_DRV_STATE_READY)  ||
              (self->state == HAL_DRV_STATE_ACTIVE) ||
              (self->state == HAL_DRV_STATE_HALF)   ||
              (self->state == HAL_DRV_STATE_FULL)   ||
              (self->state == HAL_DRV_STATE_ERROR),
              "invalid state");

if (self->state != HAL_DRV_STATE_READY) {
  dac_lld_stop_conversion(self);
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
  _dac_reset_i(self);
}

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert((self->state == HAL_DRV_STATE_READY)  ||
              (self->state == HAL_DRV_STATE_ACTIVE) ||
              (self->state == HAL_DRV_STATE_HALF)   ||
              (self->state == HAL_DRV_STATE_FULL)   ||
              (self->state == HAL_DRV_STATE_ERROR),
              "invalid state");
if (self->state != HAL_DRV_STATE_READY) {
  dac_lld_stop_conversion(self);
  self->samples = NULL;
  self->depth   = 0U;
  self->grpp    = NULL;
  self->state   = HAL_DRV_STATE_READY;
  _dac_reset_s(self);
}
osalSysUnlock();

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert(self->thread == NULL, "already waiting");
msg = dacStartConversionI(self, grpp, samples, depth);
if (msg == HAL_RET_SUCCESS) {
  msg = dacSynchronizeStateS(self, HAL_DRV_STATE_FULL, TIME_INFINITE);
}
osalSysUnlock();

return msg;

msg_t msg;

osalDbgCheck(self != NULL);
osalDbgCheckClassS();
osalDbgCheck((state == HAL_DRV_STATE_HALF) ||
             (state == HAL_DRV_STATE_FULL));
osalDbgAssert(self->state == HAL_DRV_STATE_ACTIVE, "invalid state");
osalDbgAssert(self->thread == NULL, "already waiting");

self->sync_state = state;
msg = osalThreadSuspendTimeoutS(&self->thread, timeout);
self->sync_state = HAL_DRV_STATE_STOP;

return msg;

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();
msg = dacSynchronizeStateS(self, state, timeout);
osalSysUnlock();

return msg;

daceventflags_t flags;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
flags = self->events & mask;
self->events &= ~mask;
osalSysRestoreStatusX(sts);

return flags;

dacerror_t errors;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
errors = self->errors & mask;
self->errors &= ~mask;
osalSysRestoreStatusX(sts);

return errors;

msg_t msg;

if (config != NULL) {
  self->config = __dac_setcfg_impl(self, config);
  if (self->config == NULL) {
    return HAL_RET_CONFIG_ERROR;
  }
}

self->samples = NULL;
self->depth   = 0U;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;

msg = dac_lld_start(self);
if (msg != HAL_RET_SUCCESS) {
  self->config = NULL;
}

return msg;

dac_lld_stop(self);
self->samples = NULL;
self->depth   = 0U;
self->grpp    = NULL;
self->events  = 0U;
self->errors  = 0U;
